from collections import Counter
# First create a counter of words across each word
# Traverse the list with this approach and put each one into the map
# indexed by counter item's frozenset
class Solution:
    def groupAnagrams(self, strs: List[str]) -> List[List[str]]:
        anagram_hashmap = {}
        for word in strs:
            char_counter_frozenset = frozenset(Counter(word).items())
            if char_counter_frozenset in anagram_hashmap:
                anagram_hashmap[char_counter_frozenset].append(word)
            else: 
                anagram_hashmap[char_counter_frozenset] = [word]
        # need to output list from map
        output = []
        for word_list in anagram_hashmap.values():
            output.append(word_list)
        return output

from collections import Counter

class Solution:
    def hasDuplicate(self, nums: List[int]) -> bool:
        occurance_counter = Counter(nums)
        for k, v in occurance_counter.items():
            if v > 1:
                return True
        return False

from collections import Counter
class Solution:
    def isAnagram(self, s: str, t: str) -> bool:
        s_counter = Counter(s)
        t_counter = Counter(t)
        return s_counter == t_counter

class Solution:
    def twoSum(self, nums: List[int], target: int) -> List[int]:
        hash_map = {}
        output_list = []
        for index, num in enumerate(nums):
            difference_to_target = target - num
            if difference_to_target in hash_map:
                return [hash_map[difference_to_target], index]
            hash_map[num] = index
        return output_list

from typing import List


def get_word_length(word: str) -> int:
    return len(word)

def get_abs_val(num: int) -> int:
    return abs(num)

def sort_words(words: List[str]) -> List[str]:
    return sorted(words, key=get_word_length, reverse=True)


def sort_numbers(numbers: List[int]) -> List[int]:
    return sorted(numbers, key = get_abs_val)


